// build-brand-positioning — Validate and Extract Brand Signals
// Validates required upstream inputs and extracts brand signals for LLM prompt.
//
// CLOUD MODE: all data arrives via n8n item pipeline from orchestrator.
//             market_intelligence is passed inline (no disk read).
// SELF-HOSTED: same pipeline. market_intelligence is also passed inline
//              from orchestrator (forwarded from build-market-intelligence output).
//
// Intake-provided brand preferences (brand_role, tone_of_voice, trust_style,
// conversion_style, objection_handling_style) are treated as HARD CONSTRAINTS
// and must not be overridden by LLM synthesis.

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

const input = $input.first().json;
const storeProfile = input.store_profile;
const marketIntelligence = input.market_intelligence;
const intakePayload = input.normalized_intake_payload;
const runtimeConfig = input.runtime_config;
const projectId = input.project_id;

// Propagate cloud_mode from upstream if set
if (!cloudMode && runtimeConfig && runtimeConfig.cloud_mode) {
  cloudMode = true;
}

// Required inputs
if (!storeProfile || !storeProfile.store_id) {
  throw new Error('MISSING_ARTIFACT: store_profile with store_id is required. Run build-store-profile first.');
}
if (!marketIntelligence) {
  throw new Error('MISSING_ARTIFACT: market_intelligence is required. Run build-market-intelligence first.');
}
if (!intakePayload) {
  throw new Error('MISSING_ARTIFACT: normalized_intake_payload is required. Run intake-store-input first.');
}
if (!runtimeConfig) {
  throw new Error('MISSING_RUNTIME_CONFIG: runtime_config is required.');
}
if (!projectId) {
  throw new Error('MISSING_INPUT: project_id is required.');
}

// Required store_profile fields
const profileRequired = ['store_id', 'vertical', 'price_positioning', 'primary_market', 'store_type'];
const profileMissing = profileRequired.filter(f => !storeProfile[f]);
if (profileMissing.length > 0) {
  throw new Error(`MISSING_ARTIFACT: store_profile missing required fields: ${profileMissing.join(', ')}`);
}

// Required market_intelligence fields
const miRequired = ['audience_segments', 'core_problems', 'purchase_motivators', 'trust_factors', 'competitor_types', 'positioning_goals'];
const miMissing = miRequired.filter(f => !marketIntelligence[f] || !Array.isArray(marketIntelligence[f]) || marketIntelligence[f].length === 0);
if (miMissing.length > 0) {
  throw new Error(`MISSING_ARTIFACT: market_intelligence missing required fields: ${miMissing.join(', ')}`);
}

// Simple string sanitizer — strip dangerous chars, trim, enforce max length
const sanitize = (v, maxLen) => {
  const limit = maxLen || 500;
  if (!v || typeof v !== 'string') return null;
  return v.replace(/[<>`]/g, '').trim().slice(0, limit) || null;
};

// Extract brand signals from intake
// Classified as DIRECT (user decision, must not be overridden) or HINT (synthesis guidance)
const brandSignals = {
  // DIRECT fields — user decisions passed through exactly
  brand_role:           intakePayload.brand_role || null,
  tone_of_voice_style:  intakePayload.tone_of_voice || null,      // maps to tone_of_voice.style
  trust_proof_mode:     intakePayload.trust_style || null,        // maps to trust_style.proof_mode
  conversion_cta_style: intakePayload.conversion_style || null,   // maps to conversion_style.cta_style
  objection_handling:   intakePayload.objection_handling_style || null,

  // HINT fields — synthesis guidance
  must_feel_like:       sanitize(intakePayload.must_feel_like),
  must_not_feel_like:   sanitize(intakePayload.must_not_feel_like),
  desired_style_hints:  Array.isArray(intakePayload.desired_style_hints) ? intakePayload.desired_style_hints : [],
  forbidden_styles:     Array.isArray(intakePayload.forbidden_styles) ? intakePayload.forbidden_styles : [],
  special_notes:        sanitize(intakePayload.special_notes),
  seo_goal:             intakePayload.seo_goal || null,
  aeo_goal:             intakePayload.aeo_goal || null,
};

// Log provenance: which fields are direct vs will be synthesized
const directFields = [];
const synthesizeFields = [];
if (brandSignals.brand_role) directFields.push('brand_role'); else synthesizeFields.push('brand_role');
if (brandSignals.tone_of_voice_style) directFields.push('tone_of_voice.style'); else synthesizeFields.push('tone_of_voice.style');
if (brandSignals.trust_proof_mode) directFields.push('trust_style.proof_mode'); else synthesizeFields.push('trust_style.proof_mode');
if (brandSignals.conversion_cta_style) directFields.push('conversion_style.cta_style'); else synthesizeFields.push('conversion_style.cta_style');
if (brandSignals.objection_handling) directFields.push('objection_handling_style'); else synthesizeFields.push('objection_handling_style');

console.log('DIRECT fields from intake: ' + (directFields.join(', ') || 'none'));
console.log('SYNTHESIZE fields (LLM will generate): ' + synthesizeFields.join(', '));

return [{
  json: {
    project_id: projectId,
    runtime_config: runtimeConfig,
    store_profile: storeProfile,
    market_intelligence: marketIntelligence,
    brand_signals: brandSignals,
    direct_fields: directFields,
    synthesize_fields: synthesizeFields,
    cloud_mode: cloudMode,
  },
}];

// build-brand-positioning — Build LLM Prompt
// Assembles the structured prompt for brand positioning synthesis.
// Evidence boundary: intake signals + store profile + market intelligence only.
// DIRECT intake fields are enforced as hard constraints in the prompt.
// LLM synthesizes all remaining fields.

const input = $input.first().json;
const signals = input.brand_signals;
const profile = input.store_profile;
const mi = input.market_intelligence;
const directFields = input.direct_fields || [];

// Build direct-field constraint section for the prompt
const directConstraints = [];
if (signals.brand_role) {
  directConstraints.push('  - brand_role: "' + signals.brand_role + '" (DIRECT from user — do NOT change)');
}
if (signals.tone_of_voice_style) {
  directConstraints.push('  - tone_of_voice.style: "' + signals.tone_of_voice_style + '" (DIRECT from user — do NOT change)');
}
if (signals.trust_proof_mode) {
  directConstraints.push('  - trust_style.proof_mode: "' + signals.trust_proof_mode + '" (DIRECT from user — do NOT change)');
}
if (signals.conversion_cta_style) {
  directConstraints.push('  - conversion_style.cta_style: "' + signals.conversion_cta_style + '" (DIRECT from user — do NOT change)');
}
if (signals.objection_handling) {
  directConstraints.push('  - objection_handling_style: "' + signals.objection_handling + '" (DIRECT from user — do NOT change)');
}

// Build synthesis hints section
const hintLines = [];
if (signals.must_feel_like) hintLines.push('- Must feel like: "' + signals.must_feel_like + '"');
if (signals.must_not_feel_like) hintLines.push('- Must NOT feel like: "' + signals.must_not_feel_like + '"');
if (signals.desired_style_hints && signals.desired_style_hints.length > 0) {
  hintLines.push('- Desired style hints: ' + signals.desired_style_hints.join(', '));
}
if (signals.forbidden_styles && signals.forbidden_styles.length > 0) {
  hintLines.push('- Forbidden styles: ' + signals.forbidden_styles.join(', '));
}
if (signals.special_notes) hintLines.push('- Special notes: "' + signals.special_notes + '"');
if (signals.seo_goal) hintLines.push('- SEO goal: ' + signals.seo_goal);
if (signals.aeo_goal) hintLines.push('- AEO goal: ' + signals.aeo_goal);

// Market intelligence context (bounded for prompt efficiency)
const audienceSegmentNames = (mi.audience_segments || []).map(function(s) { return s.segment_name; }).slice(0, 3).join(', ');
const coreProblems = (mi.core_problems || []).slice(0, 4).join('; ');
const purchaseMotivators = (mi.purchase_motivators || []).slice(0, 4).join('; ');
const trustFactors = (mi.trust_factors || []).slice(0, 4).join('; ');
const competitorWeaknesses = (mi.competitor_types || [])
  .map(function(ct) { return ct.weaknesses ? ct.type_name + ': ' + (ct.weaknesses || []).slice(0, 2).join(', ') : null; })
  .filter(Boolean).slice(0, 3).join(' | ');
const positioningGoals = (mi.positioning_goals || []).slice(0, 3).join('; ');

const synthesisNote = [
  'BRAND POSITIONING — SYNTHESIS ARTIFACT: Generated by LLM from internal store signals on ' + new Date().toISOString() + '.',
  'Direct fields from user intake: ' + (directFields.length > 0 ? directFields.join(', ') : 'none') + '.',
  'All other fields are LLM-synthesized from store profile and market intelligence context.',
  'Human review is required before these values are used to drive copy generation or design decisions.',
].join(' ');

const directConstraintSection = directConstraints.length > 0
  ? 'DIRECT USER CONSTRAINTS (output these field values exactly as specified — do NOT change them):\n' + directConstraints.join('\n')
  : 'NO DIRECT USER CONSTRAINTS: synthesize all positioning fields from store and market context.';

const schemaTemplate = [
  '{',
  '  "brand_role": "one of: specialist | curator | problem-solver | premium-innovator | editorial-guide | value-leader",',
  '  "value_proposition": "short concrete statement of the store unique offer (1-2 sentences)",',
  '  "positioning_statement": "single sentence describing strategic position relative to competitor types",',
  '  "differentiators": ["specific differentiator strings grounded in market context — min 1 required"],',
  '  "brand_traits": ["adjective or short phrase — min 2 required"],',
  '  "tone_of_voice": {',
  '    "style": "one of: clear-direct | premium-confident | warm-helpful | editorial-smart | playful-bold | technical-trustworthy",',
  '    "clarity_level": "one of: very-clear | balanced | more-expressive",',
  '    "emotional_intensity": "one of: low | medium | high"',
  '  },',
  '  "trust_style": {',
  '    "proof_mode": "one of: evidence-led | social-proof-led | authority-led | guarantee-led | mixed",',
  '    "reassurance_level": "one of: light | moderate | strong"',
  '  },',
  '  "conversion_style": {',
  '    "cta_style": "one of: subtle | balanced | assertive",',
  '    "sales_pressure": "one of: low | medium | high"',
  '  },',
  '  "objection_handling_style": "one of: minimal | balanced | detailed (include if relevant)",',
  '  "visual_positioning_hint": "brief visual orientation string (include if meaningful)",',
  '  "media_style_hint": "brief media style string (include if meaningful)",',
  signals.seo_goal ? '  "seo_tone_hint": "brief SEO tone guidance",' : '',
  signals.aeo_goal ? '  "aeo_tone_hint": "brief AEO tone guidance",' : '',
  '  "forbidden_impressions": ["impression strings to avoid"],',
  '  "notes": "' + synthesisNote + '"',
  '}',
].filter(function(l) { return l !== ''; }).join('\n');

const llmPrompt = [
  'You are a brand strategist for an e-commerce store.',
  'Synthesize a structured brand positioning artifact exclusively from the store signals and market intelligence provided below.',
  '',
  'CONSTRAINTS:',
  '- Output valid JSON only. No markdown fences. No explanation outside the JSON object.',
  '- All outputs are planning hypotheses for human review — do not claim certainty.',
  '- Do NOT invent statistics, market share figures, or demographic data.',
  '- Enum values must exactly match one of the listed options for each field.',
  '',
  directConstraintSection,
  '',
  'STORE SIGNALS:',
  '- Vertical: ' + profile.vertical,
  '- Store type: ' + profile.store_type,
  '- Price positioning: ' + profile.price_positioning,
  '- Brand maturity: ' + (profile.brand_maturity || 'new'),
  '- Primary market: ' + profile.primary_market,
  '- Catalog type: ' + (profile.catalog_type || 'general'),
  '- Business model: ' + (profile.business_model || 'ecommerce'),
  '',
  'MARKET INTELLIGENCE CONTEXT (LLM-synthesized — use as strategic input):',
  '- Market category: ' + (mi.market_category || 'unknown'),
  '- Audience segments: ' + (audienceSegmentNames || 'not specified'),
  '- Core problems solved: ' + (coreProblems || 'not specified'),
  '- Purchase motivators: ' + (purchaseMotivators || 'not specified'),
  '- Trust factors: ' + (trustFactors || 'not specified'),
  '- Competitor weaknesses (differentiate from): ' + (competitorWeaknesses || 'none specified'),
  '- Positioning goals: ' + (positioningGoals || 'not specified'),
  '',
  hintLines.length > 0 ? 'SYNTHESIS HINTS FROM USER:\n' + hintLines.join('\n') : 'SYNTHESIS HINTS: None provided.',
  '',
  'SYNTHESIS GUIDANCE:',
  '- value_proposition: ground in audience core_problems and purchase_motivators',
  '- positioning_statement: one sentence on strategic position vs competitor types',
  '- differentiators: derive from competitor_types weaknesses + price_positioning + vertical strengths — avoid generic platitudes',
  '- brand_traits: adjectives or short phrases consistent with brand_role and tone_of_voice style',
  '- tone_of_voice.clarity_level defaults: clear-direct→very-clear, premium-confident→balanced, warm-helpful→balanced, editorial-smart→more-expressive, playful-bold→more-expressive, technical-trustworthy→very-clear',
  '- tone_of_voice.emotional_intensity defaults: premium-confident→medium, playful-bold→high, clear-direct→low, technical-trustworthy→low, warm-helpful→medium, editorial-smart→medium',
  '- trust_style.reassurance_level: strong for new brands or premium price tiers; moderate for established; light for value-leader with existing trust signals',
  '- conversion_style.sales_pressure: low for premium-innovator or editorial-guide; high for value-leader; medium for most others',
  '- forbidden_impressions: combine must_not_feel_like + forbidden_styles + impressions that would conflict with competitor differentiation',
  '',
  'OUTPUT JSON SCHEMA (produce exactly this structure, populated with synthesized values):',
  schemaTemplate,
].join('\n');

return [{
  json: {
    project_id: input.project_id,
    runtime_config: input.runtime_config,
    store_profile: input.store_profile,
    market_intelligence: input.market_intelligence,
    brand_signals: signals,
    direct_fields: directFields,
    cloud_mode: input.cloud_mode,
    llm_prompt: llmPrompt,
  },
}];

// build-brand-positioning — Parse, Merge, Enforce, and Write
// Parses the LLM response, enforces direct fields from intake, validates structure,
// and writes the artifact.
//
// CLOUD MODE: AJV validation and filesystem write are skipped.
//             brand_positioning is returned inline in output.
// SELF-HOSTED: Validates against schemas/brand-positioning.schema.json via AJV.
//              Writes atomically to projects/{project_id}/brand-positioning.json.
//              Updates checkpoint.json if present. Quarantines on schema failure.

let fs, path;
let cloudMode = false;
try {
  fs = require('fs');
  path = require('path');
} catch (_e) {
  cloudMode = true;
}

// LLM response from OpenAI node
const llmOutput = $input.first().json;

// Upstream context from Build LLM Prompt node
const upstream = $node['Build LLM Prompt'].json;

// Propagate cloud_mode from upstream
if (!cloudMode && upstream.cloud_mode) cloudMode = true;
if (!cloudMode && upstream.runtime_config && upstream.runtime_config.cloud_mode) cloudMode = true;

const projectId = upstream.project_id;
const runtimeConfig = upstream.runtime_config;
const storeProfile = upstream.store_profile;
const brandSignals = upstream.brand_signals;
const directFields = upstream.direct_fields || [];

// Extract text from OpenAI node output (simplifyOutput: true → message.content)
const rawText = (llmOutput.message && llmOutput.message.content)
  ? llmOutput.message.content
  : (typeof llmOutput === 'string' ? llmOutput : JSON.stringify(llmOutput));

// Parse LLM response
let brandPositioning;
try {
  let cleaned = rawText.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  }
  brandPositioning = JSON.parse(cleaned);
} catch (err) {
  throw new Error(
    'PARSE_ERROR: Failed to parse LLM response as JSON: ' + err.message +
    '. Raw response (first 500 chars): ' + String(rawText).slice(0, 500)
  );
}

// ─── Enforce DIRECT fields from intake (user decisions override LLM) ─────────

// brand_role
if (brandSignals.brand_role) {
  if (brandPositioning.brand_role !== brandSignals.brand_role) {
    console.warn('DIRECT_FIELD_ENFORCED: brand_role overriding LLM value "' + brandPositioning.brand_role + '" with user value "' + brandSignals.brand_role + '"');
  }
  brandPositioning.brand_role = brandSignals.brand_role;
}

// tone_of_voice.style
if (brandSignals.tone_of_voice_style) {
  if (!brandPositioning.tone_of_voice || typeof brandPositioning.tone_of_voice !== 'object') {
    brandPositioning.tone_of_voice = {};
  }
  if (brandPositioning.tone_of_voice.style !== brandSignals.tone_of_voice_style) {
    console.warn('DIRECT_FIELD_ENFORCED: tone_of_voice.style overriding LLM value "' + brandPositioning.tone_of_voice.style + '" with user value "' + brandSignals.tone_of_voice_style + '"');
  }
  brandPositioning.tone_of_voice.style = brandSignals.tone_of_voice_style;
}

// trust_style.proof_mode
if (brandSignals.trust_proof_mode) {
  if (!brandPositioning.trust_style || typeof brandPositioning.trust_style !== 'object') {
    brandPositioning.trust_style = {};
  }
  if (brandPositioning.trust_style.proof_mode !== brandSignals.trust_proof_mode) {
    console.warn('DIRECT_FIELD_ENFORCED: trust_style.proof_mode overriding LLM value "' + brandPositioning.trust_style.proof_mode + '" with user value "' + brandSignals.trust_proof_mode + '"');
  }
  brandPositioning.trust_style.proof_mode = brandSignals.trust_proof_mode;
}

// conversion_style.cta_style
if (brandSignals.conversion_cta_style) {
  if (!brandPositioning.conversion_style || typeof brandPositioning.conversion_style !== 'object') {
    brandPositioning.conversion_style = {};
  }
  if (brandPositioning.conversion_style.cta_style !== brandSignals.conversion_cta_style) {
    console.warn('DIRECT_FIELD_ENFORCED: conversion_style.cta_style overriding LLM value "' + brandPositioning.conversion_style.cta_style + '" with user value "' + brandSignals.conversion_cta_style + '"');
  }
  brandPositioning.conversion_style.cta_style = brandSignals.conversion_cta_style;
}

// objection_handling_style
if (brandSignals.objection_handling) {
  brandPositioning.objection_handling_style = brandSignals.objection_handling;
}

// ─── Merge forbidden_impressions from intake ──────────────────────────────────
const intakeForbiddenBase = [];
if (brandSignals.must_not_feel_like) intakeForbiddenBase.push(brandSignals.must_not_feel_like);
if (brandSignals.forbidden_styles && brandSignals.forbidden_styles.length > 0) {
  brandSignals.forbidden_styles.forEach(function(s) { intakeForbiddenBase.push('avoid-style: ' + s); });
}
const existingForbidden = Array.isArray(brandPositioning.forbidden_impressions) ? brandPositioning.forbidden_impressions : [];
const merged = [];
const seen = {};
for (const item of [...intakeForbiddenBase, ...existingForbidden]) {
  if (item && !seen[item]) { seen[item] = true; merged.push(item); }
}
if (merged.length > 0) brandPositioning.forbidden_impressions = merged;

// ─── Inject synthesis notes ───────────────────────────────────────────────────
const directFieldsList = directFields.length > 0 ? directFields.join(', ') : 'none';
brandPositioning.notes = [
  'BRAND POSITIONING — SYNTHESIS ARTIFACT:',
  'Direct fields from user intake: ' + directFieldsList + '.',
  'All other fields are LLM-synthesized from store profile and market intelligence context.',
  'Market intelligence was itself LLM-synthesized — see market-intelligence.json for its evidence boundary.',
  'Human review is required before these values are used to drive copy generation or design decisions.',
  'Generated: ' + new Date().toISOString() + '.',
  'Signals: vertical=' + storeProfile.vertical + ', market=' + storeProfile.primary_market + ', price_tier=' + storeProfile.price_positioning + '.',
].join(' ');

// ─── Inline required-field validation ────────────────────────────────────────
for (const f of ['brand_role', 'value_proposition', 'positioning_statement']) {
  if (!brandPositioning[f] || typeof brandPositioning[f] !== 'string' || !brandPositioning[f].trim()) {
    throw new Error('MISSING_FIELD: brand_positioning missing required field: ' + f);
  }
}
if (!Array.isArray(brandPositioning.differentiators) || brandPositioning.differentiators.length < 1) {
  throw new Error('SCHEMA_VIOLATION: differentiators must be a non-empty array (minItems: 1).');
}
if (!Array.isArray(brandPositioning.brand_traits) || brandPositioning.brand_traits.length < 2) {
  throw new Error('SCHEMA_VIOLATION: brand_traits must have at least 2 items (minItems: 2).');
}
for (const obj of ['tone_of_voice', 'trust_style', 'conversion_style']) {
  if (!brandPositioning[obj] || typeof brandPositioning[obj] !== 'object') {
    throw new Error('MISSING_FIELD: brand_positioning missing required nested object: ' + obj);
  }
}

// Enum validation
const brandRoleEnum = ['specialist', 'curator', 'problem-solver', 'premium-innovator', 'editorial-guide', 'value-leader'];
if (!brandRoleEnum.includes(brandPositioning.brand_role)) {
  throw new Error('SCHEMA_VIOLATION: brand_role "' + brandPositioning.brand_role + '" is not valid. Must be one of: ' + brandRoleEnum.join(', '));
}
const tovStyleEnum = ['clear-direct', 'premium-confident', 'warm-helpful', 'editorial-smart', 'playful-bold', 'technical-trustworthy'];
if (!tovStyleEnum.includes(brandPositioning.tone_of_voice.style)) {
  throw new Error('SCHEMA_VIOLATION: tone_of_voice.style "' + brandPositioning.tone_of_voice.style + '" is not valid.');
}
if (!['very-clear', 'balanced', 'more-expressive'].includes(brandPositioning.tone_of_voice.clarity_level)) {
  throw new Error('SCHEMA_VIOLATION: tone_of_voice.clarity_level "' + brandPositioning.tone_of_voice.clarity_level + '" is not valid.');
}
if (!['low', 'medium', 'high'].includes(brandPositioning.tone_of_voice.emotional_intensity)) {
  throw new Error('SCHEMA_VIOLATION: tone_of_voice.emotional_intensity "' + brandPositioning.tone_of_voice.emotional_intensity + '" is not valid.');
}
if (!['evidence-led', 'social-proof-led', 'authority-led', 'guarantee-led', 'mixed'].includes(brandPositioning.trust_style.proof_mode)) {
  throw new Error('SCHEMA_VIOLATION: trust_style.proof_mode "' + brandPositioning.trust_style.proof_mode + '" is not valid.');
}
if (!['light', 'moderate', 'strong'].includes(brandPositioning.trust_style.reassurance_level)) {
  throw new Error('SCHEMA_VIOLATION: trust_style.reassurance_level "' + brandPositioning.trust_style.reassurance_level + '" is not valid.');
}
if (!['subtle', 'balanced', 'assertive'].includes(brandPositioning.conversion_style.cta_style)) {
  throw new Error('SCHEMA_VIOLATION: conversion_style.cta_style "' + brandPositioning.conversion_style.cta_style + '" is not valid.');
}
if (!['low', 'medium', 'high'].includes(brandPositioning.conversion_style.sales_pressure)) {
  throw new Error('SCHEMA_VIOLATION: conversion_style.sales_pressure "' + brandPositioning.conversion_style.sales_pressure + '" is not valid.');
}

if (cloudMode) {
  // CLOUD SKIP: No AJV schema validation. No filesystem write.
  console.warn(
    'CLOUD_MODE: build-brand-positioning skipping AJV validation and artifact write for project: ' + projectId + '. ' +
    'brand_positioning returned inline.'
  );
  return [{
    json: {
      project_id: projectId,
      artifact_name: 'brand-positioning',
      artifact_path: null,
      brand_positioning: brandPositioning,
      runtime_config: runtimeConfig,
      status: 'SUCCESS',
      cloud_mode: true,
      cloud_warnings: [
        'AJV schema validation skipped — no schema files accessible in n8n Cloud',
        'Artifact write skipped — no filesystem in n8n Cloud',
        'Checkpoint update skipped — no filesystem in n8n Cloud',
      ],
      notes: [],
    },
  }];
}

// SELF-HOSTED: AJV schema validation
const schemaPath = path.join(runtimeConfig.ajv_schema_path, 'brand-positioning.schema.json');
if (!fs.existsSync(schemaPath)) {
  throw new Error('SCHEMA_LOAD_ERROR: brand-positioning.schema.json not found at ' + schemaPath);
}
const schema = JSON.parse(fs.readFileSync(schemaPath, 'utf8'));

let AjvClass;
try {
  AjvClass = require('ajv/dist/2020');
} catch {
  try { AjvClass = require('ajv'); } catch (err) {
    throw new Error('SCHEMA_LOAD_ERROR: AJV not available: ' + err.message);
  }
}

const ajv = new AjvClass({ allErrors: true, strict: false });
const validate = ajv.compile(schema);
const valid = validate(brandPositioning);

if (!valid) {
  const quarantineDir = path.join(runtimeConfig.project_root, projectId, '.runtime', 'quarantine');
  fs.mkdirSync(quarantineDir, { recursive: true });
  const ts = new Date().toISOString().replace(/[:.]/g, '-');
  const quarantinePath = path.join(quarantineDir, 'brand-positioning.' + ts + '.rejected.json');
  fs.writeFileSync(quarantinePath, JSON.stringify({
    quarantine_reason: 'SCHEMA_VIOLATION',
    artifact_name: 'brand-positioning',
    workflow_id: 'build-brand-positioning',
    validation_errors: validate.errors,
    timestamp: new Date().toISOString(),
    project_id: projectId,
    artifact_payload: brandPositioning,
  }, null, 2), 'utf8');
  const errorSummary = (validate.errors || []).map(function(e) { return (e.instancePath || '(root)') + ' ' + e.message; }).join('; ');
  throw new Error(
    'SCHEMA_VIOLATION: brand-positioning failed validation. Quarantined to ' + quarantinePath + '. Errors: ' + errorSummary
  );
}

// Atomic write
const projectDir = path.join(runtimeConfig.project_root, projectId);
const finalPath = path.join(projectDir, 'brand-positioning.json');
const tmpPath = path.join(projectDir, 'brand-positioning.tmp.json');
fs.mkdirSync(projectDir, { recursive: true });
fs.writeFileSync(tmpPath, JSON.stringify(brandPositioning, null, 2), 'utf8');
fs.renameSync(tmpPath, finalPath);

// Update checkpoint
const checkpointPath = path.join(runtimeConfig.project_root, projectId, '.runtime', 'checkpoint.json');
const now = new Date().toISOString();
try {
  const checkpoint = JSON.parse(fs.readFileSync(checkpointPath, 'utf8'));
  checkpoint.completed_workflows.push({
    workflow_id: 'build-brand-positioning',
    completed_at: now,
    output_artifact: 'brand-positioning.json',
    status: 'SUCCESS',
  });
  checkpoint.last_updated_timestamp = now;
  checkpoint.next_workflow = 'build-competitor-clusters';
  const cpTmp = checkpointPath + '.tmp';
  fs.writeFileSync(cpTmp, JSON.stringify(checkpoint, null, 2), 'utf8');
  fs.renameSync(cpTmp, checkpointPath);
} catch { /* non-fatal */ }

return [{
  json: {
    project_id: projectId,
    artifact_name: 'brand-positioning',
    artifact_path: finalPath,
    brand_positioning: brandPositioning,
    runtime_config: runtimeConfig,
    status: 'SUCCESS',
    notes: [],
  },
}];
